#include <iostream>
#include <queue>
using namespace std;

struct TreeNode {
	int val;
	TreeNode* left;
	TreeNode* right;
	TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution 
{
public:
	int inOrderSum(TreeNode* root) {
		if (root == nullptr)
			return 0;
		int leftSum = inOrderSum(root->left);
		int currentSum = root->val;
		int rightSum = inOrderSum(root->right);
		return leftSum + currentSum + rightSum;
	}
};

int main()
{
	int n; cin >> n;
	vector<int> arr(n);
	for (int i = 0; i < n; i++) cin >> arr[i];
	queue<TreeNode*> q;
	q.push(new TreeNode(arr[0]));
	for (int i = 1; i < 2 * n; i += 2)
	{
		TreeNode* curr = q.front(); q.pop();
		curr->left = new TreeNode(arr[i]);
		q.push(curr->left);
		if (i + 1 < 2 * n)
			curr->right = new TreeNode(arr[i + 1]);
		q.push(curr->right);
	}
	Solution solution;
	cout << solution.inOrderSum(q.front()) << endl;
	return 0;
}
